# -*- coding: utf-8 -*-
"""Replace templated Section 33 Q&A with specific interview content."""

def qa(n, q, a, e):
    return (
        f'<div class="callout"><p><strong>Q{n}:</strong> {q}</p>\n'
        f'<p><strong>Answer:</strong> {a}</p>\n'
        f'<p><em>Interviewer expects:</em> {e}</p></div>\n\n'
    )

# --- Cucumber Intermediate Q31-Q65 ---
cuc_int = [
("What are Cucumber hooks?", "Hooks are methods with @Before, @After, @BeforeStep, @AfterStep annotations. @Before runs before each scenario; @After runs after regardless of pass/fail. Use for WebDriver init/quit, screenshot capture, test data setup. Tagged hooks @Before(\"@ui\") run only for matching scenarios. Hooks live in glue package alongside step definitions.", "Driver lifecycle in hooks, not in every step definition."),
("How do you use tagged hooks?", "@Before(\"@smoke and not @api\") public void beforeSmoke(Scenario s) { }. Tag expression syntax same as runner tags. Multiple tags supported. Use for browser setup per tag, API auth for @api scenarios only. Avoid too many tagged hooks — increases complexity. Document hook-tag mapping in framework README.", "Selective setup/teardown based on scenario tags."),
("What are Data Tables in Cucumber?", "Data Tables pass structured tabular data to step definitions. In Gherkin: | name | email | followed by rows. Java: DataTable parameter, or List<Map<String,String>> for header-keyed rows. Use for form filling, expected result comparison, API payload construction. DataTable.asMaps() converts to list of maps.", "List<Map> conversion and form-filling use case."),
("How do you convert Data Tables to POJOs?", "Use @DataTableType annotation on a method: @DataTableType def User user(Map<String,String> row) { return new User(row.get(\"name\")); }. Step def accepts List<User>. Cleaner than manual map parsing. Register in glue package. Cucumber 7+ supports default data table converters.", "Custom type registration for type-safe tables."),
("What is Scenario Context in hooks?", "Scenario scenario parameter in @Before/@After provides: getName(), getId(), getSourceTagNames(), getLine(), isFailed(). Use getName() for screenshot filenames. getSourceTagNames() for conditional logic. Attach text/screenshot: scenario.attach(bytes, \"image/png\", \"Screenshot\"). Available in Cucumber 7+.", "Scenario metadata for reporting and debugging."),
("What are Doc Strings in Cucumber?", "Triple-quoted text block in Gherkin passed as String to step definition. Used for JSON payloads, long text input, expected content. Example: When I submit JSON: \"\"\"{\"name\":\"John\"}\"\"\". Step: @When(\"I submit JSON:\") public void submit(String json). Alternative to inline strings for multiline content.", "Multiline string parameter for API payloads."),
("How do you implement custom Cucumber parameters?", "Custom ParameterType: @ParameterType(\"(\\\\d+)px\") public int pixel(String px) { return Integer.parseInt(px.replace(\"px\",\"\")); }. Use in step: @Then(\"width should be {pixel}\"). Transforms matched text to custom type. Register in glue package. Reduces regex complexity in step definitions.", "ParameterType annotation for domain-specific types."),
("What is Cucumber timeline report?", "plugin = \"timeline:target/timeline\" generates HTML timeline showing scenario execution chronologically. Visualizes parallel execution, identifies bottlenecks. Each thread shown as separate row. Useful for optimizing parallel Cucumber runs. Open target/timeline/index.html after execution.", "Performance analysis of parallel scenario execution."),
("What is rerun plugin in Cucumber?", "plugin = \"rerun:target/rerun.txt\" writes failed scenario paths to file. Re-run only failures: mvn test -Dcucumber.features=@target/rerun.txt. Speeds up CI failure feedback loop. Combine with retry in hooks for flaky scenarios. Standard practice in mature CI pipelines.", "Failure-only re-execution strategy."),
("How do you organize feature files?", "One feature per application module: login.feature, checkout.feature. Group related scenarios under one Feature keyword. Place in src/test/resources/features/ mirroring app structure. Avoid mega feature files with 50+ scenarios. Use subdirectories: features/api/, features/ui/. Consistent naming: verb-noun.feature.", "Feature file organization mirroring application modules."),
("How do you reuse steps across features?", "Same step text in multiple features maps to one step definition. Design reusable, generic steps: \"I am logged in as {string}\" not \"I login with admin credentials\". Shared step definition classes in common glue package. Avoid duplicate step definitions with slightly different wording.", "Reusable generic step design philosophy."),
("What is declarative vs imperative Gherkin?", "Declarative: \"Given I am logged in\" (what, not how). Imperative: \"Given I click login button and enter user and pass\" (how). Declarative is BDD best practice — readable by business. Implementation details hidden in step definitions. Imperative Gherkin becomes unmaintainable as UI changes.", "Strong preference for declarative style with examples."),
("How do you handle waits in Cucumber steps?", "Use explicit WebDriverWait inside step definitions or Page Objects — never Thread.sleep. Wrap in page object methods: wait.until(ExpectedConditions.visibilityOfElementLocated(locator)). Keep Gherkin free of wait language. Centralize timeout values in config.properties. Log wait timeouts for debugging slow pages.", "Explicit waits in page objects, not Gherkin or sleep."),
("How do you take screenshots in Cucumber?", "@After hook: if (scenario.isFailed()) { byte[] screenshot = ((TakesScreenshot)driver).getScreenshotAs(OutputType.BYTES); scenario.attach(screenshot, \"image/png\", scenario.getName()); }. Works with Allure and Cucumber native reports. Also capture on @AfterStep for step-level debugging.", "Hook-based screenshot on failure pattern."),
("What is Cucumber strict mode?", "In older versions, strict=true failed suite on pending/undefined steps. Cucumber 7 treats undefined steps as errors by default. Use dryRun=true during development to catch undefined steps. In CI, any undefined step should fail the build immediately.", "Zero tolerance for undefined steps in CI."),
("How do you test negative scenarios in Cucumber?", "Write explicit negative scenarios: Scenario: Login with invalid password. Then step verifies error message. Use Examples table for multiple invalid inputs. Tag @negative for separate CI execution. Don't mix positive and negative in same scenario — one behavior per scenario.", "Dedicated negative scenarios with clear Then assertions."),
("What is the Rule keyword in Gherkin?", "Rule groups scenarios under a business rule. Feature: Password Policy / Rule: Minimum 8 characters / Scenario: Valid password. Improves organization in complex features. Optional — not all teams use it. Supported in Gherkin 6+. Scenarios under a Rule inherit its context.", "Business rule grouping in feature files."),
("How do you run Cucumber from Maven with tags?", "mvn test -Dcucumber.filter.tags=\"@smoke and not @wip\". Override features: -Dcucumber.features=path/to/feature. Override glue: -Dcucumber.glue=com.steps. Configure defaults in @CucumberOptions on runner class. Jenkins parameterizes tag expression per build type.", "Maven command-line tag filtering for CI."),
("What is monochrome in @CucumberOptions?", "monochrome=true removes ANSI color codes from console output. Useful for CI logs that don't support colors. Output is plain text — easier to parse in Jenkins console. Keep pretty plugin for local development with colors. Set monochrome=true in CI runner configuration.", "CI-friendly console output configuration."),
("How do you handle multiple environments in Cucumber?", "ConfigReader loads properties based on -Denv system property. @Before hook reads env and sets base URL. Environment-specific feature files rarely needed — same features, different config. Jenkins injects env-specific credentials. Never hardcode URLs in feature files or step definitions.", "Environment config externalization pattern."),
("What is snippet generation?", "When Cucumber finds undefined steps, console prints suggested step definition skeletons. snippets=CamelCase or PASCALCASE controls method naming. Use during development: run with dryRun=false, copy snippets, implement methods. Speeds up step definition creation.", "Development workflow using snippet output."),
("How do you validate API responses in Cucumber steps?", "Use REST Assured in @Then steps: response.then().statusCode(200).body(\"name\", equalTo(\"John\")). Store Response in scenario-scoped variable via PicoContainer or instance field. Separate API steps from UI steps using @api tag. API steps should not reference WebDriver.", "REST Assured integration in Then steps."),
("What is conditional execution in Cucumber?", "Tagged hooks for conditional setup. ITestContext or static flags for runtime decisions. Skip scenario: throw new PendingException(\"Feature not ready\") — marks pending/skipped. @Before hook checks environment availability and throws exception to skip. Prefer tag-based filtering over runtime skipping.", "Tag-based filtering preferred over runtime skip."),
("How do you share state between step definitions?", "PicoContainer DI (cucumber-picocontainer dependency): shared classes auto-injected into step def constructors. Instance fields in same step def class for multi-step scenarios. Scenario Context via custom World object. Never use static fields for WebDriver in parallel — use ThreadLocal.", "PicoContainer for shared state between steps."),
("What is Cucumber 7 migration from older versions?", "Package change: io.cucumber replaces cucumber.api. Update imports in step defs and hooks. junit-vintage removed — use junit-platform or TestNG. Message protocol replaces old formatter API. Update pom.xml: io.cucumber:cucumber-java:7.x, cucumber-testng:7.x. Run dryRun to verify all steps still match.", "io.cucumber package migration knowledge."),
("How do you integrate Cucumber with Spring?", "cucumber-spring dependency. @CucumberContextConfiguration on Spring config class. @Autowired beans into step definitions. Spring manages test context lifecycle. Useful for integration tests needing Spring beans, DB repositories, or service layer. @Before hook can @Autowired WebDriver bean.", "Spring context in step definitions for integration tests."),
("What is feature-level vs scenario-level tags?", "Feature-level tag applies to all scenarios in feature unless scenario has overriding tag. @smoke on Feature tags every scenario. Scenario-level tag adds to feature tags. Tag inheritance: scenario tags = feature tags + own tags. Use feature tags for module-wide categorization.", "Tag inheritance from feature to scenarios."),
("How do you name scenarios properly?", "Name describes behavior and expected outcome: \"Successful login with valid credentials\" not \"Test 1\". Include business context. Avoid technical terms in names. Scenario Outline: name describes pattern: \"Login fails with <reason>\". Consistent naming helps report readability and failure triage.", "Business-readable scenario naming convention."),
("What is the pickle runner in Cucumber?", "Pickle is internal Cucumber representation of executable scenario (compiled from AST). Each Example row creates separate Pickle. Understanding Pickles helps debug parallel execution and report mapping. Not directly exposed to users but referenced in advanced parallel configuration.", "Internal scenario representation awareness."),
("How do you handle authentication in Cucumber?", "Fast approach: API login in @Before hook, inject token/cookie into browser. UI login as dedicated scenario for login feature only. Store auth state in PicoContainer shared context. @Before(\"@authenticated\") hook performs login. @After hook clears session. Never login via UI in every scenario.", "API-based auth setup in hooks for speed."),
("What is cucumber-junit-platform-engine?", "Cucumber 7 JUnit 5 integration via junit-platform-engine. Alternative to AbstractTestNGCucumberTests. Use @Suite with @SelectClasspathResource for JUnit 5. Better IDE integration with JUnit 5. TestNG still preferred in enterprise Selenium projects for parallel and listener features.", "Awareness of JUnit 5 vs TestNG runner options."),
("How do you lint Gherkin files?", "Use gherkin-lint npm tool or review checklist: max 10 steps per scenario, no And as first step, declarative language, consistent Given-When-Then. CI can run gherkin-lint as pre-commit hook. Prevents feature file quality degradation over time.", "Gherkin quality enforcement in CI."),
("What is the difference between Cucumber and SpecFlow?", "Cucumber-JVM for Java/Kotlin. SpecFlow for .NET/C#. Both use Gherkin syntax. SpecFlow integrates with Visual Studio and Reqnroll (successor). Cucumber has larger Java community. Same BDD principles apply. Choose based on technology stack.", "Tool selection based on tech stack."),
("How do you handle file upload in Cucumber?", "Step definition: driver.findElement(By.id(\"file\")).sendKeys(absoluteFilePath). File must exist on machine running test. In CI, store test files in src/test/resources/testdata/. For remote grid, use LocalFileDetector. Never interact with OS file dialog — sendKeys to hidden input.", "sendKeys file upload pattern, not OS dialog."),
("What is scenario-level timeout in Cucumber?", "Configure via TestNG @Test(timeOut) on runner or custom @Before hook with ExecutorService and Future.get(timeout). Cucumber itself has no native scenario timeout. Wrap scenario execution or set TestNG timeout on runner class methods. Log timeout with scenario name for debugging.", "Timeout via TestNG integration or custom hook."),
]

cuc_adv = [
("How do you run Cucumber scenarios in parallel?", "cucumber.execution.parallel.enabled=true in junit-platform.properties or @DataProvider parallel with AbstractTestNGCucumberTests. Set parallel config: cucumber.execution.parallel.config.strategy=dynamic, fixed, or custom. Each scenario runs in separate thread. Requires ThreadLocal WebDriver and independent test data. Start with 2-4 threads, scale based on CI capacity.", "Parallel config properties and thread safety requirements."),
("What is PicoContainer in Cucumber?", "cucumber-picocontainer dependency enables constructor injection in step definitions. Shared objects (DriverFactory, ApiClient) injected automatically. Scenario-scoped lifecycle — new instances per scenario. Constructor: public LoginSteps(WebDriver driver, LoginPage page). Eliminates static state. Required for parallel Cucumber execution.", "Constructor injection pattern with PicoContainer."),
("How do you design Cucumber framework architecture?", "Layers: Features → Step Definitions → Page Objects/Services → Utilities. Runner classes per suite (smoke, regression). Hooks class for driver lifecycle. PicoContainer for DI. ConfigReader for environment. Separate glue packages: steps, hooks, pages, utils. One runner per tag group in CI.", "Layered architecture diagram explanation."),
("How do you test REST APIs with Cucumber?", "REST Assured in step definitions. Given sets base URI and auth. When sends request. Then validates status and body. Service Object pattern: UserApiService wraps REST Assured calls. Tag @api for API-only scenarios. No WebDriver in API steps. Store Response in shared context.", "Complete API testing layer in Cucumber framework."),
("How do you implement Cucumber with Selenium Grid?", "@Before hook creates RemoteWebDriver with grid URL and capabilities. Pass -Dgrid.url=http://hub:4444. Parallel scenarios connect to different grid nodes. Docker Compose for local grid setup. Cloud providers (BrowserStack) as managed grid. Quit driver in @After hook to release node.", "RemoteWebDriver setup in hooks for grid execution."),
("What is Cucumber message protocol?", "Standardized event format (NDJSON) for Cucumber execution. plugin = \"message:target/messages.ndjson\". Consumed by Allure, custom report generators. Replaces legacy JSON formatter internals. Enables tool-agnostic report processing. Foundation for Cucumber Reports cloud service.", "Modern reporting protocol awareness."),
("How do you publish Cucumber reports?", "publish=true in @CucumberOptions uploads to Cucumber Reports cloud. Requires Cucumber CI token. Self-hosted: generate json plugin, process with Allure or Jenkins Cucumber Report plugin. Attach html report to Jira bugs. Archive reports as CI build artifacts with retention policy.", "Report publishing in enterprise CI pipeline."),
("How do you handle dynamic data in Cucumber?", "Generate at runtime in @Before hook: String email = \"user_\" + UUID.randomUUID() + \"@test.com\". Faker library for realistic data. API creates test data, UI verifies. Store generated values in PicoContainer context for later steps. Cleanup in @After hook via API or DB.", "Runtime data generation with cleanup strategy."),
("What is shared WebDriver anti-pattern?", "Static WebDriver field shared across scenarios causes failures in parallel execution. Thread A navigates while Thread B quits driver. Fix: ThreadLocal in DriverFactory, inject via PicoContainer. One driver per scenario thread. Never pass driver as static. Code review for static driver references.", "Identify and fix shared driver anti-pattern."),
("How do you version Cucumber dependencies?", "Pin io.cucumber version in pom.xml properties: <cucumber.version>7.18.0</cucumber.version>. Align cucumber-java, cucumber-testng, cucumber-picocontainer to same version. Test with dryRun after upgrades. Watch GitHub releases for breaking changes. Automated Dependabot PRs with smoke suite validation.", "Dependency version alignment strategy."),
("How do you test microservices with Cucumber?", "Each service has feature files for its API endpoints. Shared authentication steps. Contract tests verify service interfaces. Orchestration scenarios test cross-service flows. Tag by service: @user-service, @order-service. Independent execution per service in CI. Mock external dependencies with WireMock.", "Microservice BDD organization strategy."),
("What is Cucumber anti-pattern: long scenarios?", "Scenarios with 20+ steps are unmaintainable. Split into focused scenarios with Background for shared setup. Each scenario tests one behavior. Long scenarios indicate missing abstraction in step definitions. Review feature files in PR — reject scenarios exceeding 10 steps.", "Scenario length governance in code review."),
("How do you implement custom Cucumber plugin?", "Implement ConcurrentEventListener or EventListener. Register via @CucumberOptions plugin class. Handle TestCaseStarted, TestCaseFinished events. Generate custom metrics, send to monitoring system. Advanced use case for enterprise observability integration.", "Custom event listener plugin development."),
("What is dependency injection beyond PicoContainer?", "Spring DI with cucumber-spring for Spring Boot apps. Guice with cucumber-guice. Manual DI via constructor in simple frameworks. PicoContainer is lightest for Selenium projects. Choose based on application architecture — match app's DI framework.", "DI option selection rationale."),
("How do you handle iFrames in Cucumber?", "Page Object method: driver.switchTo().frame(locator), interact, switchTo().defaultContent(). Step definition calls page object — no frame logic in Gherkin. Handle nested frames with switchTo().parentFrame(). Always return to default content in finally block to prevent context leaks.", "Frame handling encapsulated in page objects."),
("What is Cucumber filter tags property?", "System property cucumber.filter.tags overrides @CucumberOptions tags at runtime. Jenkins: mvn test -Dcucumber.filter.tags=\"@regression and @ui\". Enables same runner for different CI jobs. Takes precedence over annotation. Supports full tag expression syntax.", "Runtime tag override for CI parameterization."),
("How do you integrate Allure with Cucumber 7?", "Dependency: io.qameta.allure:allure-cucumber7-jvm. Auto-attaches scenario results. @Step annotation on step definition methods for detailed steps in report. scenario.attach() for screenshots. Generate: allure serve target/allure-results. Rich timeline, categories, severity.", "Allure + Cucumber 7 integration setup."),
("What is testable Gherkin review checklist?", "Is it declarative? One behavior per scenario? Readable by product owner? No technical locators? Reusable steps? Proper tags? Examples cover edge cases? Background minimal? Follows team style guide? Review in Three Amigos session before automation.", "Quality checklist for feature file review."),
("How do you handle OAuth in Cucumber?", "API step obtains token via client credentials or password grant. Store token in scenario context. UI step injects cookie/localStorage. Alternatively automate OAuth UI flow in dedicated @oauth tagged scenarios. Use test OAuth server or mock authorization server. Never store real OAuth secrets in feature files.", "OAuth automation strategy for test environments."),
("What is Cucumber execution dry-run vs runtime?", "dryRun=true: validates step defs, no browser/API calls. Runtime: full execution with all hooks and steps. CI pipeline: dryRun in PR validation (fast), full run on merge. Local: dryRun when adding new scenarios, runtime for development. Combine: dryRun catches missing steps before wasting CI time.", "Two-phase validation in CI pipeline."),
("How do you migrate from Cucumber 4 to 7?", "Update pom.xml dependencies to io.cucumber 7.x. Replace cucumber.api imports with io.cucumber.java.en. Update hook imports: io.cucumber.java.Before. Replace AbstractTestNGCucumberTests import. Test EventListener API if custom plugins. Run full suite with dryRun first, then runtime.", "Step-by-step migration experience."),
("What is World object in Cucumber?", "Shared context object holding scenario state: tokens, created IDs, WebDriver reference. Instantiate via PicoContainer or @Before hook. Step definitions access World's fields. Cleaner than static variables. Pattern: public class TestContext { public String orderId; public WebDriver driver; }.", "World/Context object pattern for scenario state."),
("How do you optimize slow Cucumber suites?", "Profile with timeline report. Identify slowest scenarios. Replace UI setup with API setup. Reduce unnecessary Background steps. Parallel execution. Headless browser mode. Skip non-critical scenarios in smoke. Cache authentication tokens. Target: smoke under 10 minutes, regression under 1 hour.", "Data-driven suite optimization approach."),
("What is BDD framework governance?", "Gherkin style guide document. Feature file templates. Step definition naming conventions. PR review checklist for .feature files. Regular Three Amigos sessions. Archive obsolete scenarios. Tag strategy document. Onboarding guide for new team members. Quarterly feature file audit.", "Framework governance for team scale."),
("How do you test GraphQL with Cucumber?", "HTTP client or REST Assured with GraphQL query in request body. Step: When I query GraphQL with query \"{ users { id name } }\". Then validate JSON response path. Store queries in external .graphql files for complex queries. Tag @graphql for separate execution.", "GraphQL testing approach in BDD framework."),
("What is Cucumber compatibility with JUnit 5?", "cucumber-junit-platform-engine for native JUnit 5. @Suite + @IncludeEngines(\"cucumber\"). Parallel via JUnit 5 parallel config. TestNG still more common in Selenium for ITestListener and XML suites. JUnit 5 better for Spring Boot integration test projects.", "JUnit 5 vs TestNG runner selection criteria."),
("How do you handle database in Cucumber steps?", "JDBC utility in @Then steps for validation. @Before seed data, @After cleanup. DatabaseHelper class with query/execute methods. Never embed SQL in Gherkin — keep in Java. Use test database, never production. Connection pool for parallel: HikariCP with thread-safe access.", "DB validation pattern with cleanup in hooks."),
("What is event-driven Cucumber reporting?", "ConcurrentEventListener receives events during execution. Send to Kafka, Elasticsearch, or custom dashboard in real-time. Enables live test execution monitoring in CI. Advanced pattern for large organizations with centralized quality dashboards.", "Real-time reporting architecture awareness."),
("How do you cross-validate Cucumber and TestNG reports?", "Cucumber json report + TestNG testng-results.xml should show same pass/fail counts. Discrepancies indicate runner configuration issues. Unified dashboard merges both. TestNG listener captures Cucumber scenario results. Align naming: scenario name visible in both reports.", "Report reconciliation in hybrid framework."),
("What is your Cucumber framework maintenance plan?", "Weekly: review failed scenarios, update selectors. Monthly: dependency updates, remove obsolete scenarios. Quarterly: refactor duplicated steps, optimize slow scenarios. Version control feature files with same rigor as code. Metrics: scenario count, pass rate, avg duration, undefined step count.", "Long-term BDD framework ownership plan."),
("How do you train team on Cucumber/BDD?", "Week 1: BDD concepts, Gherkin syntax. Week 2: Step definitions, hooks. Week 3: Page Objects, framework structure. Week 4: Hands-on — write feature file + automate. Pair programming for first scenarios. Gherkin style guide as reference. Three Amigos workshop for PO + Dev + QA.", "Structured team onboarding plan for BDD."),
("What is Cucumber in CI/CD quality gate?", "Fail build if: any scenario fails, undefined steps exist, pass rate below threshold. Smoke tag on every PR. Full regression on merge to main. Nightly scheduled run. Publish reports as artifacts. Slack notification on failure. Track pass rate trend over 30 days.", "CI quality gate configuration for Cucumber suites."),
("How do you handle WebDriverManager in Cucumber?", "WebDriverManager.chromedriver().setup() in @Before hook or DriverFactory. Auto-downloads matching driver version. Eliminates manual driver management. Works with local and CI. Configure in DriverFactory: WebDriverManager.firefoxdriver().setup(). Keep version pinned for CI stability.", "WebDriverManager integration in framework."),
("What is the future of Cucumber testing?", "Cucumber Open Source continues with message protocol, JUnit 5 integration. AI-assisted Gherkin generation from requirements. Self-healing step definitions. Cloud-native test execution. Integration with observability platforms. BDD remains relevant for communication — tool evolves around it.", "Forward-looking perspective on BDD tooling."),
("How do you lead BDD adoption in a team?", "Start with pilot feature, demonstrate value. Three Amigos workshops. Pair PO with QA on Gherkin writing. Show living documentation to stakeholders. Measure: reduced requirement defects, faster onboarding. Don't force 100% coverage — start with critical user journeys. Celebrate early wins.", "Change management skills for BDD adoption."),
]

